previewCss:
.darma-loader-darma-custom-395 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  width: 60px;
  aspect-ratio: 1;
  position: relative;
}.darma-loader-darma-custom-395:before,.darma-loader-darma-custom-395:after {content: "";
  position: absolute;
  border-radius: 50%;
  inset: 0;
  background:radial-gradient(circle 10px,var(--loader-color, #7c3aed) 94%,#0000),repeating-conic-gradient(from -30deg,#0000 0 60deg,var(--loader-color, #7c3aed) 61deg 120deg);
  -webkit-mask: radial-gradient(circle 15px,currentColor calc(100% - 6px),#0000 calc(100% - 5px) 94%,currentColor);
}.darma-loader-darma-custom-395:before {animation: darma-loader-darma-custom-395-l4 1s infinite;
  transform: perspective(300px) translateZ(0px)}@keyframes darma-loader-darma-custom-395-l4 {to {transform: perspective(300px) translateZ(150px);
  opacity:0}}

